 marker.addListener('click', function() {
 infowindow.open(map, marker);
 });
 });
}
function addMarkers() {
 // Loop through array of littering incidents and add markers
 for (var i = 0; i < litteringIncidents.length; i++) {
 var marker = new google.maps.Marker({
 position: {lat: litteringIncidents[i].lat, lng: litteringIncidents[i].lng},
 map: map
 });

 // Create info window for marker
 var infowindow = new google.maps.InfoWindow({
 content: litteringIncidents[i].description
 });

 // Add event listener to open info window when marker is clicked
 marker.addListener('click', function() {
 infowindow.open(map, marker);
 });

 // Add marker to list of markers
 markers.push(marker);
 }
}
